import { NextRequest, NextResponse } from 'next/server'
import { getRequestContext } from '@cloudflare/next-on-pages'

export const runtime = 'edge'

export async function GET(request: NextRequest) {
  try {
    const { env } = getRequestContext()

    // If no Cloudflare DB, return empty array (development mode fallback if needed)
    if (!env || !env.DB) {
      console.log("[v0] Database not available - returning empty products")
      return NextResponse.json([], { status: 200 })
    }

    const stmt = await env.DB.prepare(
      "SELECT * FROM products WHERE isActive = 1 ORDER BY createdAt DESC"
    ).all()

    const results = stmt?.results || []

    const products = results.map((p: any) => ({
      id: p.id,
      title: p.title || '',
      description: p.description || '',
      price: p.price || 0,
      category: p.category || 'software',
      tags: p.tags ? JSON.parse(p.tags) : [],
      imageUrl: p.imageUrl || '',
      downloadUrl: p.downloadUrl || '',
      isActive: Boolean(p.isActive),
      salesCount: p.salesCount || 0,
      pageCode: p.pageCode,
      createdBy: p.createdBy || '',
      createdAt: new Date(p.createdAt),
      updatedAt: new Date(p.updatedAt)
    }))

    return NextResponse.json(products, { status: 200 })
  } catch (err: any) {
    console.error("[v0] Products API Error:", err.message)
    return NextResponse.json([], { status: 200 })
  }
}

export async function POST(request: NextRequest) {
  try {
    const { env } = getRequestContext()

    if (!env || !env.DB) {
      console.log("[v0] Database not available - cannot create product")
      return NextResponse.json({ error: "Database not available" }, { status: 503 })
    }

    const data = await request.json()

    if (!data.title || !data.price) {
      return NextResponse.json({ error: "Title and price are required" }, { status: 400 })
    }

    const id = crypto.randomUUID()
    const now = Date.now()

    await env.DB.prepare(`
      INSERT INTO products (id, title, description, price, category, tags, imageUrl, downloadUrl, isActive, salesCount, pageCode, createdBy, createdAt, updatedAt)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(
      id, 
      data.title || '', 
      data.description || '', 
      data.price || 0, 
      data.category || 'software', 
      JSON.stringify(data.tags || []), 
      data.imageUrl || '', 
      data.downloadUrl || '', 
      data.isActive ? 1 : 0, 
      0, 
      data.pageCode || null, 
      data.createdBy || 'admin', 
      now, 
      now
    ).run()

    return NextResponse.json({ success: true, id }, { status: 201 })
  } catch (err: any) {
    console.error("[v0] POST Products Error:", err.message)
    return NextResponse.json({ error: err.message }, { status: 500 })
  }
}

