      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(
      id,
      data.userId,
      JSON.stringify(data.items || []),
      data.totalAmount || 0,
      data.status || 'pending',
      data.paymentId || null,
      now,
      now
    ).run()

    return NextResponse.json({ success: true, id }, { status: 201 })
  } catch (err: any) {
    console.error("[v0] POST Orders Error:", err.message)
    return NextResponse.json({ error: err.message }, { status: 500 })
