"use client"

import { useState, useEffect } from "react"
import { ProductCard } from "@/components/product-card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import { Card, CardContent } from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Slider } from "@/components/ui/slider"
import { Search, Filter, Heart, Star, TrendingUp } from "lucide-react"
import { fetchProducts } from "@/lib/d1-client"
import type { Product } from "@/lib/types"

export default function ProductsPage() {
  const [products, setProducts] = useState<Product[]>([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState("")
  const [selectedCategory, setSelectedCategory] = useState("all")
  const [priceRange, setPriceRange] = useState([0, 100000])
  const [sortBy, setSortBy] = useState<"relevance" | "price_low" | "price_high" | "rating" | "newest">("relevance")
  const [showFilters, setShowFilters] = useState(false)
  const [favorites, setFavorites] = useState<Set<string>>(new Set())

  useEffect(() => {
    const loadData = async () => {
      try {
        const fetchedProducts = await fetchProducts()
        // Ensure we have an array
        if (Array.isArray(fetchedProducts)) {
          setProducts(fetchedProducts)
        } else {
          setProducts([])
        }
      } catch (error) {
        console.error("[v0] Failed to load products:", error)
        setProducts([])
      } finally {
        setLoading(false)
      }
    }
    loadData()
  }, [])

  const filteredProducts = (products || [])
    .filter((product) => {
      if (!product || !product.title || !product.description) return false
      const matchesSearch =
        product.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        product.description.toLowerCase().includes(searchTerm.toLowerCase())
      const matchesCategory = selectedCategory === "all" || product.category === selectedCategory
      const matchesPrice = product.price >= priceRange[0] && product.price <= priceRange[1]
      return matchesSearch && matchesCategory && matchesPrice && product.isActive
    })
    .sort((a, b) => {
      switch (sortBy) {
        case "price_low":
          return a.price - b.price
        case "price_high":
          return b.price - a.price
        case "rating":
          return (b.rating || 0) - (a.rating || 0)
        case "newest":
          return (b.createdAt?.getTime() || 0) - (a.createdAt?.getTime() || 0)
        default:
          return 0
      }
    })

  const categories = Array.from(new Set((products || []).filter(p => p && p.category).map((p) => p.category))) as string[]

  const toggleFavorite = (productId: string) => {
    const newFavorites = new Set(favorites)
    if (newFavorites.has(productId)) {
      newFavorites.delete(productId)
    } else {
      newFavorites.add(productId)
    }
    setFavorites(newFavorites)
  }

  return (
    <main className="min-h-screen bg-gradient-to-b from-gray-50 to-white">
      {/* Hero Section */}
      <div className="bg-primary text-primary-foreground py-8 mb-8">
        <div className="container mx-auto px-4">
          <h1 className="text-3xl font-bold mb-6">Browse All Products</h1>
          <div className="relative">
            <Search className="absolute left-3 top-3 h-5 w-5 opacity-50" />
            <Input
              placeholder="Search for products, brands and more..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10 bg-white text-gray-900 border-0 h-12 text-lg rounded-lg"
            />
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 pb-12">
        <div className="flex gap-6">
          {/* Sidebar Filters - Desktop */}
          <aside className={`${showFilters ? "block" : "hidden"} md:block w-full md:w-72 flex-shrink-0`}>
            <Card className="sticky top-24 shadow-lg border-0">
              <CardContent className="p-6 space-y-6">
                {/* Header */}
                <div className="flex items-center justify-between">
                  <h3 className="font-bold text-lg flex items-center gap-2">
                    <Filter className="h-5 w-5 text-primary" />
                    Filters
                  </h3>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => {
                      setSelectedCategory("all")
                      setPriceRange([0, 100000])
                      setSortBy("relevance")
                    }}
                    className="text-xs"
                  >
                    Reset
                  </Button>
                </div>

                {/* Sort By */}
                <div className="space-y-3 border-b pb-4">
                  <h4 className="font-semibold text-sm">Sort By</h4>
                  <div className="space-y-2">
                    {[
                      { value: "relevance", label: "Relevance" },
                      { value: "price_low", label: "Price: Low to High" },
                      { value: "price_high", label: "Price: High to Low" },
                      { value: "rating", label: "Highest Rated" },
                      { value: "newest", label: "Newest First" },
                    ].map((option) => (
                      <label key={option.value} className="flex items-center gap-2 cursor-pointer hover:bg-gray-50 p-2 rounded transition">
                        <input
                          type="radio"
                          name="sort"
                          value={option.value}
                          checked={sortBy === option.value}
                          onChange={(e) => setSortBy((e.target as HTMLInputElement).value as any)}
                          className="w-4 h-4 accent-primary"
                        />
                        <span className="text-sm">{option.label}</span>
                      </label>
                    ))}
                  </div>
                </div>

                {/* Categories */}
                <div className="space-y-3 border-b pb-4">
                  <h4 className="font-semibold text-sm">Category</h4>
                  <div className="space-y-2">
                    {["all", ...categories].map((cat) => (
                      <label key={cat} className="flex items-center gap-2 cursor-pointer hover:bg-gray-50 p-2 rounded transition">
                        <Checkbox
                          checked={selectedCategory === cat}
                          onCheckedChange={() => setSelectedCategory(cat)}
                          className="accent-primary"
                        />
                        <span className="text-sm capitalize font-medium">{cat === "all" ? "All Products" : cat}</span>
                      </label>
                    ))}
                  </div>
                </div>

                {/* Price Range */}
                <div className="space-y-3">
                  <h4 className="font-semibold text-sm">Price Range</h4>
                  <Slider
                    value={priceRange}
                    onValueChange={setPriceRange}
                    min={0}
                    max={100000}
                    step={1000}
                    className="w-full"
                  />
                  <div className="flex items-center justify-between bg-gray-50 p-2 rounded">
                    <span className="text-sm font-medium">${priceRange[0].toLocaleString()}</span>
                    <span className="text-xs text-muted-foreground">to</span>
                    <span className="text-sm font-medium">${priceRange[1].toLocaleString()}</span>
                  </div>
                </div>
              </CardContent>
            </Card>
          </aside>

          {/* Main Content */}
          <div className="flex-1">
            {/* Results Header */}
            <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-6 gap-4">
              <div>
                <h2 className="text-2xl font-bold">
                  {filteredProducts.length} {filteredProducts.length === 1 ? "Product" : "Products"}
                </h2>
                <p className="text-sm text-muted-foreground mt-1">
                  {selectedCategory !== "all" ? `Showing results for ${selectedCategory}` : "Browse our collection"}
                </p>
              </div>
              <Button
                variant="outline"
                size="sm"
                onClick={() => setShowFilters(!showFilters)}
                className="md:hidden w-full flex items-center justify-center gap-2"
              >
                <Filter className="h-4 w-4" />
                {showFilters ? "Hide Filters" : "Show Filters"}
              </Button>
            </div>

            {/* Loading State */}
            {loading && (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {[...Array(8)].map((_, i) => (
                  <Card key={i} className="animate-pulse">
                    <CardContent className="p-4 space-y-4">
                      <div className="bg-gray-200 h-56 rounded-lg" />
                      <div className="bg-gray-200 h-4 w-full rounded" />
                      <div className="bg-gray-200 h-4 w-2/3 rounded" />
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}

            {/* Products Grid */}
            {!loading && filteredProducts.length > 0 && (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredProducts.map((product) => (
                  <div key={product.id} className="relative group">
                    {/* Favorite Button */}
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => toggleFavorite(product.id)}
                      className="absolute top-3 right-3 z-10 bg-white hover:bg-gray-100 shadow-md rounded-full"
                    >
                      <Heart
                        className={`h-5 w-5 ${favorites.has(product.id) ? "fill-red-500 text-red-500" : "text-gray-400"}`}
                      />
                    </Button>

                    {/* Discount Badge */}
                    {product.discountPrice && (
                      <Badge className="absolute top-3 left-3 z-10 bg-red-500 text-white font-semibold">
                        {Math.round(((product.price - product.discountPrice) / product.price) * 100)}% OFF
