import { NextRequest, NextResponse } from 'next/server'
import { getRequestContext } from '@cloudflare/next-on-pages'

export const runtime = 'edge'

export async function POST(request: NextRequest) {
  try {
    const { env } = getRequestContext()
    const data = await request.json()

    if (!data.uid || !data.email) {
      return NextResponse.json({ error: "Missing uid or email" }, { status: 400 })
    }

    if (!env || !env.DB) {
      // Graceful fallback if DB not ready
      return NextResponse.json({ success: true, message: "DB not connected" }, { status: 200 })
    }

    // Check if user exists
    const existingUser: any = await env.DB.prepare("SELECT * FROM users WHERE uid = ?").bind(data.uid).first()

    const now = Date.now()

    // Determine Role: If email matches env var, force admin, otherwise keep existing or default to user
    const adminEmail = process.env.NEXT_PUBLIC_ADMIN_EMAIL || "";
    let role = 'user';

    if (data.email.toLowerCase() === adminEmail.toLowerCase()) {
      role = 'admin';
    } else if (existingUser) {
      role = existingUser.role; // Keep existing role
    }

    if (existingUser) {
      // Update existing user (update login time/info)
      await env.DB.prepare(`
        UPDATE users 
        SET email = ?, displayName = ?, role = ?, updatedAt = ?
        WHERE uid = ?
      `).bind(
        data.email,
        data.displayName || existingUser.displayName,
        role,
        now,
        data.uid
      ).run()
    } else {
      // Insert new user
      await env.DB.prepare(`
        INSERT INTO users (uid, email, displayName, role, createdAt, updatedAt)
        VALUES (?, ?, ?, ?, ?, ?)
      `).bind(
        data.uid,
        data.email,
        data.displayName || 'User',
        role,
        now,
        now
      ).run()
    }

    return NextResponse.json({ success: true, role }, { status: 200 })
  } catch (err: any) {
    console.error("[v0] Sync User Error:", err.message)
    return NextResponse.json({ error: err.message }, { status: 500 })
  }
}

