import { type NextRequest, NextResponse } from "next/server";
import { getRequestContext } from '@cloudflare/next-on-pages'

export const runtime = 'edge';

export async function POST(request: NextRequest) {
  try {
    const formData = await request.formData();
    const file = formData.get("file") as File;

    if (!file) {
      return NextResponse.json({ message: "No file provided" }, { status: 400 });
    }

    const { env } = getRequestContext();
    // Try both env.VAR (Cloudflare) and process.env.VAR (Node compat/Build time)
    const BOT_TOKEN = env.TELEGRAM_BOT_TOKEN || process.env.TELEGRAM_BOT_TOKEN;
    const CHAT_ID = env.TELEGRAM_CHAT_ID || process.env.TELEGRAM_CHAT_ID;

    if (!BOT_TOKEN || !CHAT_ID) {
      console.error("[v0] Telegram not configured - BOT_TOKEN or CHAT_ID missing");
      // Return a placeholder URL for development
      return NextResponse.json({ url: `/placeholder.svg?height=400&width=600&text=Image+Placeholder` }, { status: 200 });
    }

    try {
      // 1. Send Document/Photo to Telegram Chat
      const telegramFormData = new FormData();
      telegramFormData.append("chat_id", CHAT_ID as string);
      telegramFormData.append("document", file); // Sending as document to prevent compression, or use 'photo'

      const uploadRes = await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/sendDocument`, {
        method: "POST",
        body: telegramFormData,
      });

      const uploadData = await uploadRes.json();

      if (!uploadData.ok) {
        throw new Error(uploadData.description || "Telegram API Error");
      }

      // 2. Get File Path
      const fileId = uploadData.result.document.file_id;
      const filePathRes = await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/getFile?file_id=${fileId}`);
      const filePathData = await filePathRes.json();

      if (!filePathData.ok) {
        throw new Error("Failed to retrieve file path");
      }

      const filePath = filePathData.result.file_path;

      // 3. Construct Public URL
      // Note: This URL requires the bot token to be part of the path, which is public.
      const fileUrl = `https://api.telegram.org/file/bot${BOT_TOKEN}/${filePath}`;

      return NextResponse.json({ url: fileUrl });
    } catch (telegramError: any) {
      console.error("[v0] Telegram upload error:", telegramError.message);
      // Return placeholder on Telegram error
      return NextResponse.json({ url: `/placeholder.svg?height=400&width=600&text=Image+Failed` }, { status: 200 });
    }

  } catch (error: any) {
    console.error("[v0] Upload error:", error.message);
    return NextResponse.json({ message: error.message }, { status: 500 });
  }
}

