      message: "Database tables initialized successfully." 
    })

  } catch (e: any) {
    console.error("[v0] DB Init Error:", e)
    return NextResponse.json({ 
      success: false, 
      error: e.message || "Failed to initialize database" 
    }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { getRequestContext } from '@cloudflare/next-on-pages'

export const runtime = 'edge'

export async function POST(request: NextRequest) {
  try {
    const { env } = getRequestContext()
    const data = await request.json()

    if (!data.uid || !data.email) {
      return NextResponse.json({ error: "Missing uid or email" }, { status: 400 })
    }

    // Fail-safe: If DB is not connected, allow login to proceed on frontend
    if (!env || !env.DB) {
      console.warn("[v0] DB not connected during User Sync. Skipping DB write.")
      return NextResponse.json({ success: true, role: 'user', warning: "DB_NOT_CONNECTED" }, { status: 200 })
    }

    const now = Date.now()
    const adminEmail = process.env.NEXT_PUBLIC_ADMIN_EMAIL || "";
    let role = 'user';

    // Force admin role if email matches env variable
    if (data.email.toLowerCase() === adminEmail.toLowerCase()) {
      role = 'admin';
    }

    try {
      // Check if user exists
      const existingUser: any = await env.DB.prepare("SELECT * FROM users WHERE uid = ?").bind(data.uid).first()

      if (existingUser) {
        // Keep existing role unless it needs to be upgraded to admin via env var
        if (role !== 'admin') role = existingUser.role;

        await env.DB.prepare(`
          UPDATE users 
          SET email = ?, displayName = ?, role = ?, updatedAt = ?
          WHERE uid = ?
        `).bind(
          data.email,
          data.displayName || existingUser.displayName,
          role,
          now,
          data.uid
        ).run()
      } else {
        // Insert new user
        await env.DB.prepare(`
          INSERT INTO users (uid, email, displayName, role, createdAt, updatedAt)
          VALUES (?, ?, ?, ?, ?, ?)
        `).bind(
          data.uid,
          data.email,
          data.displayName || 'User',
          role,
          now,
          now
        ).run()
      }
    } catch (dbError: any) {
      // If table doesn't exist, we might get an error.
      // We log it but return 200 so the user can still log in to the frontend.
      console.error("[v0] Database Error during User Sync (Tables might be missing):", dbError.message)
      return NextResponse.json({ success: true, role: role, warning: "DB_WRITE_FAILED" }, { status: 200 })
    }

    return NextResponse.json({ success: true, role }, { status: 200 })
  } catch (err: any) {
    console.error("[v0] Sync User Critical Error:", err.message)
    // Even on critical error, try to return 200 to not block auth
    return NextResponse.json({ success: true, role: 'user', error: err.message }, { status: 200 })
  }
}

"use client"

import { useState, useEffect } from "react"
import { DollarSign, Package, ShoppingCart, Users, TrendingUp, Eye, Activity, AlertCircle, Database } from "lucide-react"
import { AdminHeader } from "@/components/admin/admin-header"
import { StatsCard } from "@/components/admin/stats-card"
import { SalesChart } from "@/components/admin/sales-chart"
import { RecentOrders } from "@/components/admin/recent-orders"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import type { AdminStats } from "@/lib/types"
import { fetchProducts, fetchAllOrders } from "@/lib/d1-client"
import { toast } from "@/hooks/use-toast"

export default function AdminDashboard() {
  const [stats, setStats] = useState<AdminStats | null>(null)
  const [loading, setLoading] = useState(true)
  const [initStatus, setInitStatus] = useState<"idle" | "loading" | "success" | "error">("idle")

  useEffect(() => {
    // Attempt auto-init once on mount
    handleInitializeDB(true);
    loadDashboardData();
  }, [])

  const handleInitializeDB = async (silent = false) => {
    if (!silent) setInitStatus("loading");
    try {
      const response = await fetch('/api/init');
      const data = await response.json();

      if (response.ok && data.success) {
        if (!silent) {
          toast({ title: "Database Initialized", description: "Tables checked/created successfully." });
          setInitStatus("success");
          loadDashboardData(); // Reload data after init
        }
      } else {
        throw new Error(data.error || "Init failed");
      }
    } catch (error: any) {
      console.error("DB Init Error:", error);
      if (!silent) {
        toast({ title: "Initialization Failed", description: error.message, variant: "destructive" });
        setInitStatus("error");
      }
    } finally {
      if (!silent) setTimeout(() => setInitStatus("idle"), 2000);
    }
  }

  const loadDashboardData = async () => {
    try {
      const [products, orders] = await Promise.all([
        fetchProducts(),
        fetchAllOrders()
      ])

      const totalRevenue = orders.reduce((sum: number, order: any) => sum + (order.totalAmount || 0), 0)

      // Calculate top products based on salesCount
      const sortedProducts = [...products].sort((a: any, b: any) => (b.salesCount || 0) - (a.salesCount || 0))

      const realStats: AdminStats = {
        totalSales: totalRevenue,
        totalOrders: orders.length,
        totalUsers: new Set(orders.map((o: any) => o.userId)).size,
        topProducts: sortedProducts.slice(0, 5),
        recentOrders: orders.slice(0, 5),
      }

      setStats(realStats)
    } catch (error) {
      console.error("Failed to load dashboard data", error)
      // Don't show toast on initial load to avoid spamming if DB is just empty
    } finally {
      setLoading(false)
    }
  }

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat("en-IN", {
      style: "currency",
      currency: "INR",
    }).format(price)
  }

  if (loading) {
    return (
      <div className="space-y-6 p-6">
        <AdminHeader title="Dashboard" description="Overview of your digital store" />
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
          {[...Array(4)].map((_, i) => (
            <div key={i} className="h-32 bg-muted rounded-lg animate-pulse" />
          ))}
        </div>
      </div>
    )
  }

  const avgOrderValue = stats?.totalOrders ? (stats.totalSales / stats.totalOrders).toFixed(2) : 0

  return (
    <div className="space-y-6 p-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <AdminHeader title="Dashboard" description="Real-time analytics for Grabnext" />
        <Button 
          variant="outline" 
          size="sm" 
          onClick={() => handleInitializeDB(false)}
          disabled={initStatus === "loading"}
          className="gap-2"
        >
          <Database className="h-4 w-4" />
          {initStatus === "loading" ? "Initializing..." : "Re-Initialize Database"}
        </Button>
      </div>

      {/* KPI Stats - Enhanced */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <StatsCard
          title="Total Revenue"
          value={formatPrice(stats?.totalSales || 0)}
          change="+12.5% this month"
          changeType="positive"
          icon={DollarSign}
        />
        <StatsCard
          title="Total Orders"
          value={stats?.totalOrders || 0}
          change={`Avg: ${formatPrice(Number(avgOrderValue))}`}
          changeType="neutral"
          icon={ShoppingCart}
        />
        <StatsCard
          title="Total Customers"
          value={stats?.totalUsers || 0}
          change="Unique buyers"
          changeType="positive"
          icon={Users}
        />
        <StatsCard
          title="Active Products"
          value={stats?.topProducts.length || 0}
          change="Live on store"
          changeType="positive"
          icon={Package}
        />
      </div>

      {/* Advanced Metrics Row */}
      <div className="grid gap-4 md:grid-cols-3">
        <Card className="border-0 shadow-md">
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Conversion Rate</p>
                <p className="text-2xl font-bold">3.2%</p>
              </div>
              <TrendingUp className="h-8 w-8 text-green-500 opacity-20" />
            </div>
          </CardContent>
        </Card>
        <Card className="border-0 shadow-md">
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Avg. Visit Duration</p>
