              <p className="font-medium text-sm">Add New Product</p>
              <p className="text-xs text-muted-foreground">Create and list a new item</p>
            </div>
            <div className="p-3 bg-green-50 rounded-lg border border-green-200 cursor-pointer hover:bg-green-100 transition">
